SELECT *
FROM kios_orders
WHERE user_id = #{userId}

    AND status = #{status}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM kios_orders
WHERE user_id = #{userId}

    AND status = #{status}

SELECT * FROM kios_orders WHERE 1=1
AND status = #{status}
AND (order_number ILIKE CONCAT('%', #{search}, '%') OR shipping_address ILIKE CONCAT('%', #{search}, '%'))
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM kios_orders WHERE 1=1
AND status = #{status}
AND (order_number ILIKE CONCAT('%', #{search}, '%') OR shipping_address ILIKE CONCAT('%', #{search}, '%'))

SELECT COUNT(*) > 0
FROM kios_orders o
JOIN order_items oi ON o.id = oi.order_id
WHERE o.user_id = #{userId}
AND oi.product_id = #{productId}
AND o.status = 'DELIVERED'

SELECT COUNT(*)
FROM kios_orders
WHERE status = #{status}

SELECT *
FROM kios_orders
WHERE created_at >= NOW() - INTERVAL '1 ' || #{period}
